mapper.select:
select ndgss.*
from nx_distributer_goods_shelf_stock as ndgss
left join nx_distributer_goods_shelf_stock_reduce as ir on ir.nx_dgssr_nx_stock_id = ndgss.nx_distributer_goods_shelf_stock_id
and ir.nx_dgssr_type = 2

    and ir.nx_dgssr_date = #{inventoryDate}


    and ir.nx_dgssr_week = #{inventoryWeek}


    and ir.nx_dgssr_month = #{inventoryMonth}

where ndgss.nx_dgss_nx_shelf_goods_id = #{shelfGoodsId}
and ndgss.nx_dgss_rest_weight > 0
and ndgss.nx_dgss_status = 0
and ir.nx_distributer_goods_shelf_stock_reduce_id IS NULL
order by ndgss.nx_dgss_date ASC

select *
from nx_distributer_goods
where nx_distributer_goods_id = #{value}

select count(*)
from nx_distributer_goods as ndg
left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id =
ndg.nx_dg_dfg_goods_grand_id


        and nx_dg_distributer_id = #{disId}


        and ndg.nx_dg_purchase_auto = #{goodsType}



        and ndg.nx_dg_goods_is_hidden = #{isHidden}


        and ndg.nx_dg_nx_goods_id = #{nxGoodsId}


        and ndg.nx_dg_nx_goods_id is null


        and ndg.nx_dg_will_price_one = #{willPrice}


        and ndg.nx_dg_buying_price = #{buyPrice}


        and nx_dg_purchase_auto = #{autoType}


        and ndg.nx_dg_supplier_id is not null and ndg.nx_dg_supplier_id > 0


        and ndg.nx_dg_supplier_id = #{supplierId}


        and ndg.nx_dg_dfg_goods_father_id = #{fatherId}


        and ndg.nx_dg_dfg_goods_grand_id = #{grandId}


        and ndfg.nx_dfg_fathers_father_id = #{greatGrandId}


        and ndg.nx_dg_carton_unit IS NOT NULL AND TRIM(ndg.nx_dg_carton_unit) != ''


        and (ndg.nx_dg_carton_unit IS NULL OR TRIM(ndg.nx_dg_carton_unit) = '')


        and ndg.nx_dg_trace_report_id IS NOT NULL


        and ndg.nx_dg_trace_report_id IS NULL

SELECT ndg.*, ndfg.*, nddg.*, ndo.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name FROM ( SELECT ndg.nx_distributer_goods_id FROM nx_distributer_goods AS ndg LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN nx_goods AS ng_sub ON ng_sub.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_goods AS ng_father_sub ON ng_father_sub.nx_goods_id = ndfg.nx_dfg_nx_goods_id LEFT JOIN nx_department_dis_goods AS nddg ON nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id AND nddg.nx_DDG_department_id = #{nxDepId} LEFT JOIN nx_department_orders AS ndo ON ndo.nx_DO_dis_goods_id = ndg.nx_distributer_goods_id AND ndo.nx_DO_purchase_status < 5 AND ndo.nx_DO_department_id = #{nxDepId}
AND ndfg.nx_dfg_fathers_father_id = #{grandId}
AND ndg.nx_dg_goods_is_hidden = #{isHidden}
AND ndg.nx_dg_dfg_goods_father_id IS NOT NULL
AND ndg.nx_dg_dfg_goods_father_id IS NULL
AND ndg.nx_dg_purchase_auto = #{goodsType}
ORDER BY COALESCE(ng_father_sub.nx_goods_sort, ndfg.nx_dfg_father_goods_sort), COALESCE(ng_sub.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng_sub.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort) LIMIT #{offset}, #{limit} ) AS limited_goods JOIN nx_distributer_goods AS ndg ON ndg.nx_distributer_goods_id = limited_goods.nx_distributer_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN nx_goods AS ng ON ng.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_goods AS ng_father ON ng_father.nx_goods_id = ndfg.nx_dfg_nx_goods_id LEFT JOIN nx_department_dis_goods AS nddg ON nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id AND nddg.nx_DDG_department_id = #{nxDepId} LEFT JOIN nx_department_orders AS ndo ON ndo.nx_DO_dis_goods_id = ndg.nx_distributer_goods_id AND ndo.nx_DO_purchase_status < 5 AND ndo.nx_DO_department_id = #{nxDepId} LEFT JOIN nx_distributer_standard AS nds ON nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_alias AS nda ON nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_goods_shelf_goods AS ndgsg ON ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_goods_shelf AS ndgs ON ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id;

SELECT ndg.*, ndfg.*, nddg.*, ndo.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name, ndgss.nx_distributer_goods_shelf_stock_id, ndgss.nx_dgss_nx_distributer_id, ndgss.nx_dgss_nx_dis_goods_id, ndgss.nx_dgss_nx_dis_goods_father_id, ndgss.nx_dgss_weight, ndgss.nx_dgss_price, ndgss.nx_dgss_price_carton, ndgss.nx_dgss_selling_price, ndgss.nx_dgss_selling_price_carton, ndgss.nx_dgss_subtotal, ndgss.nx_dgss_rest_weight, ndgss.nx_dgss_rest_weight_show_standard, ndgss.nx_dgss_rest_subtotal, ndgss.nx_dgss_date, ndgss.nx_dgss_full_time, ndgss.nx_dgss_loss_subtotal, ndgss.nx_dgss_nx_pur_goods_id, ndgss.nx_dgss_status, ndgss.nx_dgss_stock_image, ndgss.nx_dgss_stock_remark FROM ( SELECT ndg.nx_distributer_goods_id FROM nx_distributer_goods AS ndg LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN nx_goods AS ng_sub ON ng_sub.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_goods AS ng_father_sub ON ng_father_sub.nx_goods_id = ndfg.nx_dfg_nx_goods_id LEFT JOIN nx_department_dis_goods AS nddg ON nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id AND nddg.nx_DDG_department_id = #{nxDepId} LEFT JOIN nx_department_orders AS ndo ON ndo.nx_DO_dis_goods_id = ndg.nx_distributer_goods_id AND ndo.nx_DO_purchase_status < 5 AND ndo.nx_DO_department_id = #{nxDepId}
AND ndfg.nx_dfg_fathers_father_id = #{grandId}
AND ndg.nx_dg_goods_is_hidden = #{isHidden}
AND ndg.nx_dg_dfg_goods_father_id IS NOT NULL
AND ndg.nx_dg_dfg_goods_father_id IS NULL
ORDER BY COALESCE(ng_father_sub.nx_goods_sort, ndfg.nx_dfg_father_goods_sort), COALESCE(ng_sub.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng_sub.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort) LIMIT #{offset}, #{limit} ) AS limited_goods JOIN nx_distributer_goods AS ndg ON ndg.nx_distributer_goods_id = limited_goods.nx_distributer_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN nx_goods AS ng ON ng.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_goods AS ng_father ON ng_father.nx_goods_id = ndfg.nx_dfg_nx_goods_id LEFT JOIN nx_department_dis_goods AS nddg ON nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id AND nddg.nx_DDG_department_id = #{nxDepId} LEFT JOIN nx_department_orders AS ndo ON ndo.nx_DO_dis_goods_id = ndg.nx_distributer_goods_id AND ndo.nx_DO_purchase_status < 5 AND ndo.nx_DO_department_id = #{nxDepId} LEFT JOIN nx_distributer_standard AS nds ON nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_alias AS nda ON nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_goods_shelf_goods AS ndgsg ON ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_goods_shelf AS ndgs ON ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id LEFT JOIN nx_distributer_goods_shelf_stock AS ndgss ON ndgss.nx_dgss_nx_dis_goods_id = ndg.nx_distributer_goods_id AND ndgss.nx_dgss_status = 0 ORDER BY COALESCE(ng_father.nx_goods_sort, ndfg.nx_dfg_father_goods_sort), COALESCE(ng.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort), ndgss.nx_dgss_date DESC;

select *
from nx_distributer_goods
where nx_dg_nx_goods_id = #{nxSGoodsId};

select ndg.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name from nx_distributer_goods as ndg left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id
and nx_dg_distributer_id = #{disId}
and nx_dg_goods_pinyin = #{searchPinyin}
and nx_dg_goods_standardname = #{standard}
and nx_dg_goods_standard_weight = #{standardWeight}
and nx_dg_goods_brand = #{brand}
and nx_dg_nx_goods_id is not null

