        and nx_dg_goods_brand = #{brand}


        and nx_dg_goods_place = #{place}


        and nx_dg_nx_goods_id is not null

select * from nx_distributer_goods


        and nx_dg_distributer_id = #{disId}


        and nx_dg_goods_name = #{goodsName}


        and nx_dg_goods_brand = #{goodsBrand}


        and nx_dg_goods_detail = #{goodsDetail}


        and nx_dg_goods_standardname = #{goodsStandard}


        and nx_dg_goods_standard_weight = #{standardWeight}


        and nx_dg_goods_place = #{place}



        and nx_dg_dfg_goods_father_id = #{fatherId}


SELECT
ndg.*,
ng.*,
ndgsg.nx_distributer_goods_shelf_goods_id,
ndgsg.nx_DGSG_shelf_sort,
ndgsg.nx_DGSG_dis_goods_id,
ndgsg.nx_DGSG_shelf_id,
ndgsg.nx_DGSG_sort,
ndgsg.nx_DGSG_shelf_layer,
ndgsg.nx_DGSG_is_duplicate,
ndgs.nx_distributer_goods_shelf_name as shelf_name
FROM
(   
SELECT
ndg.nx_distributer_goods_id,
ndg.nx_dg_goods_sort,
ndg.nx_dg_goods_sons_sort
FROM nx_distributer_goods AS ndg
LEFT JOIN nx_goods AS ng_sub ON ng_sub.nx_goods_id = ndg.nx_dg_nx_goods_id


        and ndg.nx_dg_supplier_id = #{supplierId}


        and ndg.nx_dg_nx_goods_id = #{nxGoodsId}


        and ndg.nx_dg_nx_goods_id != #{nxGoodsIdNotEqual}


        and ndg.nx_dg_nx_father_id = #{nxFatherId}


        and ndg.nx_dg_nx_great_grand_id = #{nxGreatGrandFatherId}


        and ndg.nx_dg_distributer_id = #{disId}


        and ndg.nx_dg_nx_goods_id = #{goodsId}


        and ndg.nx_dg_dfg_goods_father_id = #{dgFatherId}


        and ndg.nx_dg_dfg_goods_grand_id = #{grandId}


        and ndg.nx_dg_goods_sort >= #{dayuSort}


        and ndg.nx_dg_goods_is_hidden = #{isHidden}


        and ndg.nx_dg_purchase_auto = #{autoType}


        and ndg.nx_dg_nx_goods_id is null


        and ndg.nx_dg_will_price_one = #{willPrice}


        and ndg.nx_dg_buying_price = #{buyPrice}


        and ndg.nx_dg_carton_unit IS NOT NULL AND TRIM(ndg.nx_dg_carton_unit) != ''


        and (ndg.nx_dg_carton_unit IS NULL OR TRIM(ndg.nx_dg_carton_unit) = '')


        and ndg.nx_dg_trace_report_id IS NOT NULL


        and ndg.nx_dg_trace_report_id IS NULL


ORDER BY COALESCE(ng_sub.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng_sub.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort)

    LIMIT #{offset}, #{limit}

) AS page

JOIN nx_distributer_goods AS ndg ON ndg.nx_distributer_goods_id = page.nx_distributer_goods_id
LEFT JOIN nx_goods AS ng ON ng.nx_goods_id = ndg.nx_dg_nx_goods_id
LEFT JOIN nx_distributer_goods_shelf_goods AS ndgsg ON ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id
LEFT JOIN nx_distributer_goods_shelf AS ndgs ON ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id

ORDER BY COALESCE(ng.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort)

select * from nx_distributer_goods


        and nx_dg_nx_father_id = #{nxFatherId}


        and nx_dg_nx_goods_id = #{nxGoodsId}


        and nx_dg_distributer_id = #{disId}


        and nx_dg_goods_name = #{goodsName}


        and nx_dg_goods_pinyin = #{searchPinyin}

select * from nx_distributer_goods as ndg
left join nx_distributer_father_goods as ndfg on
    ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id


        and nx_dg_distributer_id = #{disId}


        and nx_dg_nx_goods_id = #{nxGoodsId}


        and ndg.nx_dg_supplier_id = #{supplierId}


        and nx_dg_purchase_auto = #{autoType}


