select * from nx_distributer_goods as ndg
 left join nx_goods as ng  on ng.nx_goods_id = ndg.nx_dg_nx_father_id


        and nx_dg_nx_goods_id = #{nxGoodsId}


        and ndg.nx_dg_supplier_id = #{supplierId}


        and nx_dg_purchase_auto = #{autoType}

select ndg.*, njs.*, nju.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name from nx_distributer_goods as ndg left join nx_jrdh_supplier as njs on ndg.nx_dg_supplier_id = njs.nx_jrdh_supplier_id left join nx_jrdh_user as nju on nju.nx_jrdh_user_id= njs.nx_jrdhs_user_id left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id left join nx_goods as ng on ng.nx_goods_id = ndg.nx_dg_nx_goods_id
and ndg.nx_dg_dfg_goods_grand_id = #{grandId}
and ndg.nx_dg_dfg_goods_grand_id = #{fatherId}
and ndg.nx_dg_goods_is_hidden = #{isHidden}
and ndg.nx_dg_supplier_id is not null and ndg.nx_dg_supplier_id > 0
and ndg.nx_dg_carton_unit IS NOT NULL AND TRIM(ndg.nx_dg_carton_unit) != ''
and (ndg.nx_dg_carton_unit IS NULL OR TRIM(ndg.nx_dg_carton_unit) = '')
and ndg.nx_dg_trace_report_id IS NOT NULL
and ndg.nx_dg_trace_report_id IS NULL
order by COALESCE(ng.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort)

select *
from  nx_distributer_goods as ndg
         left join gb_distributer_goods as gdg on gdg.gb_dg_nx_distributer_goods_id = ndg.nx_distributer_goods_id  and gdg.gb_dg_distributer_id = #{gbDisId}
         left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id
         left join nx_goods as ng on ng.nx_goods_id = ndg.nx_dg_nx_goods_id
         left join nx_goods as ng_father on ng_father.nx_goods_id = ndfg.nx_dfg_nx_goods_id


      and  ndfg.nx_dfg_fathers_father_id = #{grandId}


        and  ndfg.nx_distributer_father_goods_id = #{fatherId}

    and ndg.nx_dg_goods_is_hidden = 0  and ndg.nx_dg_nx_goods_id != -1


order by COALESCE(ng_father.nx_goods_sort, ndfg.nx_dfg_father_goods_sort), COALESCE(ng.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort)

    limit #{offset}, #{limit}

select ndg.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name from nx_distributer_goods as ndg left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id
and nx_dg_distributer_id = #{disId}
and nda.nx_DA_alias_name = #{alias}
and nda.nx_DA_dis_goods_id = #{disGoodsId}
and nx_dg_goods_standardname = #{standard}

select * from nx_distributer_goods as ndg
left join gb_distributer_goods as gdg on gdg.gb_dg_nx_distributer_goods_id = ndg.nx_distributer_goods_id
and gdg.gb_dg_distributer_id = #{gbDisId} and gdg.gb_dg_nx_distributer_goods_id = ndg.nx_distributer_goods_id
left join nx_goods as ng on ng.nx_goods_id = ndg.nx_dg_nx_goods_id


        and ndg.nx_dg_distributer_id = #{disId}


        and ndg.nx_dg_nx_goods_id = #{goodsId}


        and ndg.nx_dg_dfg_goods_father_id = #{dgFatherId}


        and ndg.nx_dg_dfg_goods_grand_id = #{grandId}


        and ndg.nx_dg_goods_is_hidden = #{isHidden}


order by COALESCE(ng.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort)

select * from ( select dg.nx_distributer_goods_id from nx_distributer_goods as dg left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = dg.nx_distributer_goods_id left join nx_goods as ng_sub on ng_sub.nx_goods_id = dg.nx_dg_nx_goods_id where nx_dg_distributer_id = #{disId} and dg.nx_dg_goods_is_hidden = 0 and ndgsg.nx_DGSG_dis_goods_id is null order by COALESCE(ng_sub.nx_goods_sort, dg.nx_dg_goods_sort), COALESCE(ng_sub.nx_goods_sons_sort, dg.nx_dg_goods_sons_sort)
limit #{offset}, #{limit}
) as t1 inner join nx_distributer_goods as dg on dg.nx_distributer_goods_id = t1.nx_distributer_goods_id left join nx_distributer_standard as ds on ds.nx_DS_dis_goods_id = dg.nx_distributer_goods_id left join nx_distributer_alias as da on da.nx_DA_dis_goods_id = dg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = dg.nx_distributer_goods_id left join nx_distributer_purchase_goods as ndpg on ndpg.nx_DPG_dis_goods_id = dg.nx_distributer_goods_id and ndpg.nx_DPG_purchase_type = 11 and ndpg.nx_DPG_status < #{status} left join nx_distributer_goods_shelf_stock as ndgss on ndgss.nx_dgss_nx_dis_goods_id = dg.nx_distributer_goods_id and ndgss.nx_dgss_rest_weight > 0 left join nx_goods as ng on ng.nx_goods_id = dg.nx_dg_nx_goods_id order by COALESCE(ng.nx_goods_sort, dg.nx_dg_goods_sort), COALESCE(ng.nx_goods_sons_sort, dg.nx_dg_goods_sons_sort)

select * from nx_distributer_goods as ndg left join nx_distributer as nd on nd.nx_distributer_id = ndg.nx_dg_distributer_id
and nx_dg_nx_goods_id = #{nxGoodsId}
order by ndg.nx_dg_out_total_weight DESC

SELECT ndg.*, ng.*, ndfg.*, ndo.*, gdg.*, gddg.*, gds.*, nds.*, nda.* FROM ( SELECT ndg.nx_distributer_goods_id FROM nx_distributer_goods AS ndg LEFT JOIN nx_goods AS ng_sub ON ng_sub.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN nx_goods AS ng_father_sub ON ng_father_sub.nx_goods_id = ndfg.nx_dfg_nx_goods_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = ndg.nx_dg_nx_goods_id AND gdg.gb_dg_distributer_id = #{gbDisId} LEFT JOIN gb_department_dis_goods AS gddg ON gddg.gb_DDG_department_id = #{gbDepId} AND gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id
AND ndfg.nx_dfg_fathers_father_id = #{grandId}
AND ndg.nx_dg_goods_is_hidden = #{isHidden}
ORDER BY COALESCE(ng_father_sub.nx_goods_sort, ndfg.nx_dfg_father_goods_sort), COALESCE(ng_sub.nx_goods_sort, ndg.nx_dg_goods_sort), COALESCE(ng_sub.nx_goods_sons_sort, ndg.nx_dg_goods_sons_sort) LIMIT #{offset}, #{limit} ) AS limited_goods LEFT JOIN nx_distributer_goods AS ndg ON ndg.nx_distributer_goods_id = limited_goods.nx_distributer_goods_id LEFT JOIN nx_goods AS ng ON ng.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN nx_goods AS ng_father ON ng_father.nx_goods_id = ndfg.nx_dfg_nx_goods_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = ndg.nx_dg_nx_goods_id AND gdg.gb_dg_distributer_id = #{gbDisId} LEFT JOIN gb_department_dis_goods AS gddg ON gddg.gb_DDG_department_id = #{gbDepId} AND gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id LEFT JOIN gb_department_goods_stock AS gds ON gds.gb_dgs_gb_dep_dis_goods_id = gddg.gb_department_dis_goods_id LEFT JOIN nx_distributer_standard AS nds ON nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_alias AS nda ON nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_department_orders AS ndo ON ndo.nx_DO_dis_goods_id = ndg.nx_distributer_goods_id AND ndo.nx_DO_status < 3 AND ndo.nx_DO_gb_department_id = #{gbDepId}

select ndg.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name from nx_distributer_goods as ndg left join nx_department_orders as ndo on ndo.nx_DO_department_id = #{depId} and ndg.nx_distributer_goods_id = ndo.nx_DO_dis_goods_id and ndo.nx_DO_status < 3 left join nx_department_dis_goods as nddg on nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id and nddg.nx_DDG_department_id = #{depId} left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id
and nx_dg_distributer_id = #{disId}
AND nx_dg_goods_name like CONCAT('%', #{searchStr}, '%')
and nx_dg_goods_standardname = #{standard}
and nx_dg_nx_goods_id is not null

select ndg.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name from nx_distributer_goods as ndg left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id
and nx_dg_distributer_id = #{disId}
and nx_dg_goods_pinyin LIKE CONCAT('%', #{searchPinyin}, '%')
and nx_dg_goods_standardname = #{standard}
and nx_dg_nx_goods_id is not null

select ndg.*, nds.*, nda.*, ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_dis_goods_id, ndgsg.nx_DGSG_shelf_id, ndgsg.nx_DGSG_sort, ndgsg.nx_DGSG_shelf_layer, ndgsg.nx_DGSG_is_duplicate, ndgs.nx_distributer_goods_shelf_name as shelf_name from nx_distributer_goods as ndg left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_DGSG_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_goods_shelf as ndgs on ndgs.nx_distributer_goods_shelf_id = ndgsg.nx_DGSG_shelf_id
and nx_dg_distributer_id = #{disId}
AND nda.nx_DA_alias_pinyin LIKE CONCAT('%', #{searchPinyin}, '%')
and nda.nx_DA_dis_goods_id = #{disGoodsId}
and nx_dg_goods_standardname = #{standard}

select nx_distributer_goods_id from nx_distributer_goods as dg left join nx_distributer_father_goods as f on f.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_father_id left join nx_distributer_father_goods as g on g.nx_distributer_father_goods_id = f.nx_dfg_fathers_father_id left join nx_distributer_father_goods as gg on gg.nx_distributer_father_goods_id = g.nx_dfg_fathers_father_id left join nx_goods as ng_dg on ng_dg.nx_goods_id = dg.nx_dg_nx_goods_id left join nx_goods as ng_f on ng_f.nx_goods_id = f.nx_dfg_nx_goods_id left join nx_goods as ng_g on ng_g.nx_goods_id = g.nx_dfg_nx_goods_id left join nx_goods as ng_gg on ng_gg.nx_goods_id = gg.nx_dfg_nx_goods_id
AND dg.nx_dg_distributer_id = #{disId}
AND dg.nx_dg_pull_off = #{pull}
AND dg.nx_dg_goods_is_hidden = #{isHidden}
AND dg.nx_dg_dfg_goods_father_id IS NOT NULL
AND dg.nx_dg_dfg_goods_father_id IS NULL
and dg.nx_dg_dfg_goods_grand_id in
#{id}
and gg.nx_dfg_nx_goods_id is not null
ORDER BY COALESCE(ng_gg.nx_goods_sort, gg.nx_dfg_father_goods_sort), COALESCE(ng_g.nx_goods_sort, g.nx_dfg_father_goods_sort), COALESCE(ng_f.nx_goods_sort, f.nx_dfg_father_goods_sort), COALESCE(ng_dg.nx_goods_sort, dg.nx_dg_goods_sort),COALESCE(ng_dg.nx_goods_sons_sort, dg.nx_dg_goods_sons_sort)

select nx_distributer_goods_id from nx_distributer_goods as dg left join nx_distributer_father_goods as f on f.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_father_id left join nx_distributer_father_goods as g on g.nx_distributer_father_goods_id = f.nx_dfg_fathers_father_id left join nx_distributer_father_goods as gg on gg.nx_distributer_father_goods_id = g.nx_dfg_fathers_father_id left join nx_goods as ng_dg on ng_dg.nx_goods_id = dg.nx_dg_nx_goods_id left join nx_goods as ng_f on ng_f.nx_goods_id = f.nx_dfg_nx_goods_id left join nx_goods as ng_g on ng_g.nx_goods_id = g.nx_dfg_nx_goods_id left join nx_goods as ng_gg on ng_gg.nx_goods_id = gg.nx_dfg_nx_goods_id
AND dg.nx_dg_distributer_id = #{disId}
AND dg.nx_dg_pull_off = #{pull}
AND dg.nx_dg_goods_is_hidden = #{isHidden}
AND dg.nx_dg_dfg_goods_father_id IS NOT NULL
AND dg.nx_dg_dfg_goods_father_id IS NULL
and dg.nx_dg_dfg_goods_grand_id in
#{id}
and gg.nx_dfg_nx_goods_id is not null and dg.nx_dg_purchase_auto = 1
ORDER BY COALESCE(ng_gg.nx_goods_sort, gg.nx_dfg_father_goods_sort), COALESCE(ng_g.nx_goods_sort, g.nx_dfg_father_goods_sort), COALESCE(ng_f.nx_goods_sort, f.nx_dfg_father_goods_sort), COALESCE(ng_dg.nx_goods_sort, dg.nx_dg_goods_sort),COALESCE(ng_dg.nx_goods_sons_sort, dg.nx_dg_goods_sons_sort)
